package comp310.tests.hw03;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotSame;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.awt.Color;
import java.awt.Graphics;
import java.awt.Point;
import java.lang.reflect.Proxy;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicReference;

import org.junit.jupiter.api.Test;

import hw03.model.Ball;
import hw03.model.IUpdateStrategy;
import hw03.model.strategy.ExpandingStrategy;
import hw03.model.strategy.ExplodingStrategy;
import hw03.model.strategy.StraightStrategy;
import hw03.model.strategy.SwitcherStrategy;
import provided.utils.dispatcher.IDispatcher;
import provided.utils.displayModel.IDimension;

class StrategyAgentTest {

	private final IDimension mockDim = new IDimension() {
		@Override
		public int getWidth() {
			return 100;
		}

		@Override
		public int getHeight() {
			return 100;
		}
	};

	private Ball makeBall(Point loc, Point vel, int radius) {
		return new Ball(loc, vel, Color.RED, radius, mockDim, new StraightStrategy());
	}

	@SuppressWarnings("unchecked")
	private IDispatcher<Graphics> countingDispatcher(AtomicInteger addCount, AtomicReference<Object> lastAdded) {
		return (IDispatcher<Graphics>) Proxy.newProxyInstance(IDispatcher.class.getClassLoader(),
				new Class<?>[] { IDispatcher.class }, (proxy, method, args) -> {
					if ("addObserver".equals(method.getName())) {
						addCount.incrementAndGet();
						lastAdded.set(args[0]);
					}
					return null;
				});
	}

	@Test
	void testExplodingStrategyAddsOneNewBallAfterBounce() {
		ExplodingStrategy strategy = new ExplodingStrategy();
		Ball ball = makeBall(new Point(95, 50), new Point(3, 0), 10);
		AtomicInteger addCount = new AtomicInteger(0);
		AtomicReference<Object> lastAdded = new AtomicReference<>();
		IDispatcher<Graphics> disp = countingDispatcher(addCount, lastAdded);

		ball.bounce();
		strategy.updateState(disp, ball);
		strategy.updateState(disp, ball);

		assertEquals(1, addCount.get());
		assertTrue(lastAdded.get() instanceof Ball);
		assertNotSame(ball, lastAdded.get());
	}

	@Test
	void testExpandingStrategyTurnsAroundAtMinimumRadius() {
		ExpandingStrategy strategy = new ExpandingStrategy();
		Ball ball = makeBall(new Point(50, 50), new Point(1, 1), 60);

		for (int i = 0; i < 27; i++) {
			strategy.updateState(null, ball);
		}
		assertEquals(5, ball.getRadius());

		strategy.updateState(null, ball);
		assertEquals(7, ball.getRadius());
	}

	@Test
	void testSwitcherDelegatesToCustomStrategy() {
		SwitcherStrategy switcher = new SwitcherStrategy();
		Ball ball = makeBall(new Point(20, 20), new Point(1, 2), 10);
		IUpdateStrategy custom = (disp, target) -> target.setRadius(target.getRadius() + 6);

		switcher.switchStrategy(custom);
		switcher.updateState(null, ball);

		assertEquals(16, ball.getRadius());
	}
}

